<?php require 'vendor/autoload.php'; $app = require_once 'bootstrap/app.php'; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); Illuminate\Support\Facades\Schema::table('dish_recipes', function($t) { $t->unsignedBigInteger('level_id')->nullable()->after('dish_id'); $t->foreign('level_id')->references('id')->on('levels')->onDelete('cascade'); }); Illuminate\Support\Facades\DB::statement('UPDATE dish_recipes dr JOIN dish_recipe_levels drl ON dr.id = drl.dish_recipe_id SET dr.level_id = drl.level_id'); echo 'Done!';
